class Solution:
    def kthCharacter(self, k: int, operations: List[int]) -> str:
        length = 1
        shift = 0
        for op in operations:
            if op == 0:
                length *= 2
            else:
                shift += 1
                length *= 2
        k -= 1
        while length > 1:
            if k < length // 2:
                length //= 2
            else:
                k -= length // 2
                shift += 1
                length //= 2
        return chr((ord('a') + shift) % 26)
```
